function removeKey(head, key) {
    // Remove leading nodes with key
    while (head !== null && head.data === key) {
        head = head.next;
    }

    if (head === null) return null;

    let curr = head;
    while (curr !== null && curr.next !== null) {
        if (curr.next.data === key) {
            curr.next = curr.next.next;
        } else {
            curr = curr.next;
        }
    }
    return head;
}
